1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const DEDUCTIBLE = 100;
23	const CAP_MULTIPLIER = 2;
24	
25	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
26	type Customer = { yearsWithMHPCO: number };
27	type Damage = { itemType: string; amount: number };
28	type Incident = { cause: string; damages: Damage[] };
29	type QuoteStep = { op: "quote"; items: Item[] };
30	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
31	type Step = QuoteStep | ClaimStep;
32	type Scenario = { customer: Customer; steps: Step[] };
33	
34	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
35	
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const LOYALTY_DISCOUNT_RATE = 0.2;
40	const LOYALTY_YEARS_THRESHOLD = 2;
41	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
42	
43	type QuoteResult = { premium: number };
44	type ClaimResult = { payout: number; remainingCap: number };
45	type StepResult = QuoteResult | ClaimResult;
46	
47	const COMPONENT_BLOCK_SIZE = 3;
48	const COMPONENT_BLOCK_PREMIUM = 60;
49	
50	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
51	
52	const sumByLookup = (items: Item[], table: Record<string, number>): number =>
53	  items.reduce((sum, item) => sum + table[item.type], 0);
54	
55	const groupByType = (items: Item[]): Item[][] =>
56	  Object.values(Object.groupBy(items, (item) => item.type));
57	
58	const basePremiumForGroup = (group: Item[]): number =>
59	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumByLookup(group, BASE_PREMIUMS);
60	
61	const basePremiumFor = (items: Item[]): number =>
62	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
63	
64	type RateRule<T> = { rate: number; applies: (input: T) => boolean };
65	
66	const SURCHARGE_RULES: RateRule<Item>[] = [
67	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
68	  {
69	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	    applies: (item) => enchantmentOf(item) >= HIGH_ENCHANTMENT_THRESHOLD,
71	  },
72	];
73	
74	const surchargeForRule = (items: Item[], rule: RateRule<Item>): number =>
75	  items
76	    .filter(rule.applies)
77	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rule.rate, 0);
78	
79	const surchargesFor = (items: Item[]): number =>
80	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
81	
82	type PolicyContext = { customer: Customer; isFollowUp: boolean };
83	
84	const POLICY_DISCOUNT_RULES: RateRule<PolicyContext>[] = [
85	  {
86	    rate: LOYALTY_DISCOUNT_RATE,
87	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
88	  },
89	  {
90	    rate: FOLLOW_UP_DISCOUNT_RATE,
91	    applies: ({ isFollowUp }) => isFollowUp,
92	  },
93	];
94	
95	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
96	  POLICY_DISCOUNT_RULES.filter((rule) => rule.applies(context)).reduce(
97	    (total, rule) => total + base * rule.rate,
98	    0,
99	  );
100	
101	const validateItems = (items: Item[]): void => {
102	  const unknown = items.find((item) => !(item.type in BASE_PREMIUMS));
103	  if (unknown) {
104	    throw new Error(`Unknown item type: "${unknown.type}"`);
105	  }
106	};
107	
108	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
109	  validateItems(items);
110	  const base = basePremiumFor(items);
111	  const surcharges = surchargesFor(items);
112	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
113	  const firstInsurance = base * FIRST_INSURANCE_RATE;
114	  return {
115	    premium: Math.ceil(base + surcharges - discounts + firstInsurance + PROCESSING_FEE),
116	  };
117	};
118	
119	const isFollowUpStep = (index: number): boolean => index > 0;
120	
121	type Policy = { items: Item[]; remainingCap: number };
122	
123	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
124	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
125	
126	const createPolicy = (items: Item[]): Policy => ({
127	  items,
128	  remainingCap: CAP_MULTIPLIER * sumByLookup(items, INSURANCE_VALUES),
129	});
130	
131	const reimbursementFor = (item: Item, amount: number): number =>
132	  enchantmentOf(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
133	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
134	    : amount;
135	
136	const payoutForDamage = (damage: Damage, policy: Policy): number => {
137	  const item = policy.items.find((it) => it.type === damage.itemType);
138	  const reimbursement = item ? reimbursementFor(item, damage.amount) : damage.amount;
139	  return Math.max(0, reimbursement - DEDUCTIBLE);
140	};
141	
142	const countBy = <T>(xs: T[], keyOf: (x: T) => string): Record<string, number> =>
143	  xs.reduce<Record<string, number>>((acc, x) => {
144	    const key = keyOf(x);
145	    acc[key] = (acc[key] ?? 0) + 1;
146	    return acc;
147	  }, {});
148	
149	const validateNoNegativeDamages = (damages: Damage[]): void => {
150	  const negative = damages.find((d) => d.amount < 0);
151	  if (negative) {
152	    throw new Error(`Negative damage amount for "${negative.itemType}"`);
153	  }
154	};
155	
156	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
157	  const damageCounts = countBy(damages, (d) => d.itemType);
158	  const itemCounts = countBy(items, (i) => i.type);
159	  for (const [type, count] of Object.entries(damageCounts)) {
160	    if (count > (itemCounts[type] ?? 0)) {
161	      throw new Error(`Damage for "${type}" exceeds insured count`);
162	    }
163	  }
164	};
165	
166	const validateDamages = (damages: Damage[], items: Item[]): void => {
167	  validateNoNegativeDamages(damages);
168	  validateDamageCounts(damages, items);
169	};
170	
171	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
172	  validateDamages(incident.damages, policy.items);
173	  const uncappedPayout = incident.damages.reduce(
174	    (sum, damage) => sum + payoutForDamage(damage, policy),
175	    0,
176	  );
177	  const payout = Math.floor(Math.min(uncappedPayout, policy.remainingCap));
178	  policy.remainingCap -= payout;
179	  return { payout, remainingCap: policy.remainingCap };
180	};
181	
182	type StepContext = { customer: Customer; index: number; policies: Policy[] };
183	
184	const STEP_HANDLERS: {
185	  [K in Step["op"]]: (step: Extract<Step, { op: K }>, context: StepContext) => StepResult;
186	} = {
187	  quote: ({ items }, { customer, index, policies }) => {
188	    policies[index] = createPolicy(items);
189	    return quotePremium(items, customer, isFollowUpStep(index));
190	  },
191	  claim: (step, { policies }) => processClaim(policies[step.policy], step.incident),
192	};
193	
194	const runStep = (step: Step, context: StepContext): StepResult =>
195	  (STEP_HANDLERS[step.op] as (s: Step, c: StepContext) => StepResult)(step, context);
196	
197	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
198	  const policies: Policy[] = [];
199	  const results = steps.map((step, index) => runStep(step, { customer, index, policies }));
200	  return { results };
201	};
